173	
174	## Test Patterns
175	
176	### Testing Pure Services
177	
178	```typescript
179	describe("PureScoringService", () => {
180	  const service = new PureScoringService();
181	
182	  it("should calculate score correctly", () => {
183	    const input = {
184	      factors: [
185	        { weight: 0.5, value: 10 },
186	        { weight: 0.5, value: 20 },
187	      ],
188	    };
189	
190	    const result = service.calculateScore(input);
191	
192	    expect(result).toBe(15); // (0.5 * 10) + (0.5 * 20)
193	  });
194	});
195	```
196	
197	### Testing Persistence Services
198	
199	```typescript
200	import { mockDeep } from "vitest-mock-extended";
201	import { PrismaClient } from "@prisma/client";
202	
203	describe("ContactPersistenceService", () => {
204	  let service: ContactPersistenceService;
205	  let mockPrisma: ReturnType<typeof mockDeep<PrismaClient>>;
206	
207	  beforeEach(() => {
208	    mockPrisma = mockDeep<PrismaClient>();
209	    service = new ContactPersistenceService(mockPrisma);
210	  });
211	
212	  it("should find contacts by userId", async () => {
213	    const userId = "user-123";
214	    const mockContacts = [createMockContact({ userId })];
215	    mockPrisma.contact.findMany.mockResolvedValue(mockContacts);
216	
217	    const result = await service.findByUserId(userId);
218	
219	    expect(result).toEqual(mockContacts);
220	    expect(mockPrisma.contact.findMany).toHaveBeenCalledWith({
221	      where: { userId, deletedAt: null },
222	    });
223	  });
224	});
225	```
226	
227	### Testing Orchestrators
228	
229	```typescript
230	describe("ContactOrchestratorService", () => {
231	  let service: ContactOrchestratorService;
232	  let mockPersistence: ReturnType<typeof vi.fn>;
233	  let mockScoring: ReturnType<typeof vi.fn>;
234	
235	  beforeEach(() => {
236	    mockPersistence = {
237	      create: vi.fn(),
238	      findById: vi.fn(),
239	    };
240	    mockScoring = {
241	      calculateScore: vi.fn().mockReturnValue(75),
242	    };
243	    service = new ContactOrchestratorService(mockPersistence, mockScoring);
244	  });
245	
246	  it("should create contact and calculate score", async () => {
247	    const input = createMockContactInput();
248	    const createdContact = createMockContact(input);
249	    mockPersistence.create.mockResolvedValue(createdContact);
250	
251	    const result = await service.createContact(input);
252	
253	    expect(result.score).toBe(75);
254	    expect(mockPersistence.create).toHaveBeenCalledWith(input);
255	    expect(mockScoring.calculateScore).toHaveBeenCalled();
256	  });
257	});
258	```
259	
260	### Testing API Routes (Hono)
261	
262	```typescript
263	import { Hono } from "hono";
264	
265	function buildApp(mockService: MockContactService) {
266	  const app = new Hono();
267	  app.route("/api/contacts", createContactRoutes(mockService));
268	  return app;
269	}
270	
271	describe("POST /api/contacts", () => {
272	  it("should create contact and return 201", async () => {
273	    const body = { email: "test@example.com", name: "Test" };
274	    mockService.create.mockResolvedValue({ id: "contact-1", ...body });
275	
276	    const app = buildApp(mockService);
277	    const res = await app.request("/api/contacts", {
278	      method: "POST",
279	      headers: { "Content-Type": "application/json" },
280	      body: JSON.stringify(body),
281	    });
282	
283	    expect(res.status).toBe(201);
284	    const data = await res.json();
285	    expect(data.email).toBe(body.email);
286	  });
287	
288	  it("should return 401 for unauthenticated request", async () => {
289	    const app = buildApp(mockService);
290	    // No auth header provided
291	    const res = await app.request("/api/contacts", {
292	      method: "POST",
293	      body: JSON.stringify({}),
294	    });
295	
296	    expect(res.status).toBe(401);
297	  });
298	});
299	```
